const ov = K.forwardRef(({ projects: i }, a) => {
  const [rectTop, setRectTop] = K.useState(1000);
  const [vh, setVh] = K.useState(800);
  const [iframeHeight, setIframeHeight] = K.useState(1800);
  
  const scrollYProgress = K.useMemo(() => He(0), []);

  K.useEffect(() => {
    const handleScroll = () => {
      try {
        const parentWindow = window.parent;
        const iframe = parentWindow.document.querySelector('iframe[src*="stacking-card.html"]');
        if (iframe) {
          const rect = iframe.getBoundingClientRect();
          setRectTop(rect.top);
          setVh(parentWindow.innerHeight);
          setIframeHeight(rect.height);
          
          const totalScrollDist = rect.height - parentWindow.innerHeight;
          let progress = 0;
          if (rect.top <= 0) {
            progress = -rect.top / totalScrollDist;
          }
          progress = Math.max(0, Math.min(progress, 1));
          scrollYProgress.set(progress);
        }
      } catch (e) {}
    };

    window.parent.addEventListener('scroll', handleScroll, { passive: true });
    setTimeout(handleScroll, 100);
    return () => window.parent.removeEventListener('scroll', handleScroll);
  }, []);

  return lt.jsx("main", {
    className: "bg-transparent w-full relative",
    style: { height: `${iframeHeight}px` },
    children: lt.jsx("div", {
      className: "w-full absolute",
      style: {
        height: "500px",
        top: `${Math.max(0, Math.min(vh / 2 - 250 - rectTop, iframeHeight - 500))}px`
      },
      children: i.map((f, h) => {
        const g = 1 - (i.length - h) * .05;
        const cardNaturalTop = h * 320;
        const cardTopInParent = rectTop + cardNaturalTop;
        
        const targetStickyOffset = h * 25;
        let cardY = cardNaturalTop;
        if (rectTop < 0) {
          cardY = Math.max(targetStickyOffset, cardNaturalTop + rectTop);
        }
        
        let p = 0;
        if (vh - cardTopInParent > 0) {
          p = (vh - cardTopInParent) / vh;
        }
        p = Math.max(0, Math.min(p, 1));
        
        const cardImageScale = Eg(He(p), [0, 1], [2, 1]);

        return lt.jsx(KE, {
          i: h,
          url: f.link,
          title: f.title,
          color: f.color,
          description: f.description,
          progress: scrollYProgress,
          range: [h * .25, 1],
          targetScale: g,
          y: cardY,
          imageScale: cardImageScale
        }, `p_${h}`);
      })
    })
  });
});

